62	/**@ch 懸賞令管理器*/
63	@ccclass('WantedPosterManager')
64	export class WantedPosterManager extends Component {
65	    //#region Constants
66	    /**
67	     * @ch 需要註冊的事件列表
68	     */
69	    private static readonly EVENTS_TO_REGISTER = [
70	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
72	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
74	        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	    //#endregion Constants
78	
79	    //#region Properties
80	    @property({
81	        type: Node,
82	        tooltip: "根節點"
83	    })
84	    private m_rootNode: Node = null;
85	
86	    @property({
87	        type: [WantedPosterItem],
88	        tooltip: "懸賞令物品"
89	    })
90	    private m_wantedPosterItems: WantedPosterItem[] = [];
91	
92	    @property({
93	        type: Layout,
94	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
95	    })
96	    private m_layout: Layout = null;
97	
98	    @property({
99	        type: WantedPosterLayoutConfig,
100	        tooltip: "直向排版設定"
101	    })
102	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "橫向排版設定"
107	    })
108	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 是否已初始化*/
113	    private m_isInitialized: boolean = false;
114	    //#endregion Variables
115	
116	    //#region Lifecycle
117	    /**@ch 元件載入時調用*/
118	    onLoad() {
119	        this.RegisterEvent();
120	        this.RegisterKeyboardEvents();
121	    }
122	
123	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
124	    start() {
125	        this.ApplyLayoutByOrientation();
126	    }
127	
128	    /**@ch 元件銷毀時調用*/
129	    onDestroy() {
130	        if (!this.m_isInitialized) return;
131	        this.UnregisterEvent();
132	        this.UnregisterKeyboardEvents();
133	        this.m_isInitialized = false;
134	    }
135	    //#endregion Lifecycle
136	
137	    //#region Event Management
138	    /**@ch 註冊鍵盤事件（測試用）*/
139	    private RegisterKeyboardEvents(): void {
140	        if (!DEBUG) return;
141	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
142	    }
143	
144	    /**@ch 取消註冊鍵盤事件（測試用）*/
145	    private UnregisterKeyboardEvents(): void {
146	        if (!DEBUG) return;
147	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
148	    }
149	
150	    /**@ch 註冊事件*/
151	    private RegisterEvent() {
152	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
153	            eventManager.Register(eventName, this);
154	        });
155	        this.m_isInitialized = true;
156	    }
157	
158	    /**@ch 取消註冊事件*/
159	    private UnregisterEvent() {
160	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
161	            eventManager.UnRegister(eventName, this);
162	        });
163	    }
164	
165	    /**
166	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
167	     * @param args 事件參數
168	     * @returns 是否有效
169	     */
170	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
171	        if (typeof args[0] !== 'boolean') {
172	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
173	            return false;
174	        }
175	        return true;
176	    }
177	
178	    /**
179	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
180	     * @param args 事件參數
181	     * @returns 是否有效
182	     */
183	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
184	        if (!Array.isArray(args[0])) {
185	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
186	            return false;
187	        }
188	        return true;
189	    }
190	
191	    /**
192	     * @ch 事件回調
193	     * @param event 事件名稱
194	     * @param args 事件參數
195	     */
196	    OnEvent(event: string, ...args: any[]) {
197	        switch (event) {
198	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
199	                if (this.ValidateSetWantedPosterDataArgs(args)) {
200	                    this.SetWantedPosterData(args[0] as IBountyData[]);
201	                }
202	                break;
203	
204	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
205	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
206	                    this.SetWantedPosterUIShow(args[0] as boolean);
207	                }
208	                break;
209	
210	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
211	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
212	                break;
213	
214	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
215	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
216	                break;
217	
218	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
219	                this.HandleGameIntroComplete();
220	                break;
221	
222	            case GAME_EVENT.DEVICE_ROTATION:
223	                this.ApplyLayoutByOrientation();
224	                break;
225	
226	            default:
227	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
228	        }
229	    }
230	
231	    /**
232	     * @ch 依目前裝置方向套用對應的 Layout 設定
233	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
234	     */
235	    private ApplyLayoutByOrientation(): void {
236	        if (!this.m_layout) {
237	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
238	            return;
239	        }
240	        const isLandscape = Common.GetGameView().IsLandscape;
241	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
242	
243	        this.m_layout.type = cfg.type;
244	        this.m_layout.resizeMode = cfg.resizeMode;
245	        this.m_layout.paddingLeft = cfg.paddingLeft;
246	        this.m_layout.paddingRight = cfg.paddingRight;
247	        this.m_layout.paddingTop = cfg.paddingTop;
248	        this.m_layout.paddingBottom = cfg.paddingBottom;
249	        this.m_layout.spacingX = cfg.spacingX;
250	        this.m_layout.spacingY = cfg.spacingY;
251	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
252	        this.m_layout.alignVertical = cfg.alignVertical;
253	        this.m_layout.updateLayout();
254	    }
255	
256	    /**
257	     * @ch 處理 PLAY_MARK 事件
258	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
259	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
260	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
261	     * EH-9：resolve callback 缺失 → error（caller bug）
262	     */
263	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
264	        if (typeof resolve !== 'function') {
265	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
266	            return;
267	        }
268	        const items = this.GetItemsByBaseSymbol(baseSymbol);
269	        if (items.length === 0) {
270	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
271	            resolve();
272	            return;
273	        }
274	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
275	    }
276	
277	    /**
278	     * @ch 處理 PLAY_MARK_ACTIVE 事件
279	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
280	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
281	     * EH-9：resolve callback 缺失 → error
282	     */
283	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
284	        if (typeof resolve !== 'function') {
285	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
286	            return;
287	        }
288	        const items = this.GetItemsByBaseSymbol(baseSymbol);
289	        if (items.length === 0) {
290	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
291	            resolve();
292	            return;
293	        }
294	        Promise.all(items.map(item =>
295	            item.PlayMarkActive().then(() => { item.node.active = false; })
296	        )).then(() => resolve());
297	    }
298	
299	    /**
300	     * @ch 處理 GAME_INTRO_COMPLETE 事件
301	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）
302	     * 複用 SetWantedPosterData 顯示路徑：item inactive→active 走 BC-1（SetData + active + PlayIn），
303	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支
304	     */
305	    private HandleGameIntroComplete() {
306	        this.SetWantedPosterData([
307	            { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 },
308	        ]);
309	    }
310	    //#endregion Event Management
311	
312	    //#region Methods
313	    /**
314	     * @ch 設置懸賞令資料（前後狀態比對 — 決定 In / Out / 僅更新）
315	     *
316	     * BC-1：item 從 inactive→active(Multiple>0) → SetData + active=true + PlayIn
317	     * BC-2：item 從 active→inactive(Multiple<=0) → PlayOut → active=false
318	     * BC-12：BaseSymbol 不變 → 僅更新 multiplier label（不重播 In）
319	     * BC-13：顯示數量少→多（原本有顯示且本輪變多）→ 先讓現有全部 Out，再讓新的全部一起 In（協調進場）
320	     * EH-6：BaseSymbol 變動但仍 active → PlayOut → 重設資料 → PlayIn
321	     */
322	    private SetWantedPosterData(dataList: IBountyData[]) {
323	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
324	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
325	            return;
326	        }
327	
328	        if (dataList.length > this.m_wantedPosterItems.length) {
329	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
330	                dataList.length, '>', this.m_wantedPosterItems.length);
331	        }
332	
333	        const count = this.m_wantedPosterItems.length;
334	
335	        // BC-13：少→多協調轉場偵測——統計前後顯示數量
336	        let prevActiveCount = 0;
337	        let newActiveCount = 0;
338	        for (let i = 0; i < count; i++) {
339	            const item = this.m_wantedPosterItems[i];
340	            if (!item) continue;
341	            if (item.node.active) prevActiveCount++;
342	            const d = i < dataList.length ? dataList[i] : null;
343	            if (d !== null && d.Multiple > 0) newActiveCount++;
344	        }
345	        // 原本有顯示且本輪變多 → 走協調轉場（現有全 Out → 新的全一起 In），不走下方逐 item 比對
346	        if (prevActiveCount > 0 && newActiveCount > prevActiveCount) {
347	            this.PlayFewerToMoreTransition(dataList);
348	            return;
349	        }
350	
351	        for (let i = 0; i < count; i++) {
352	            const item = this.m_wantedPosterItems[i];
353	            if (!item) continue;
354	
355	            const prevActive = item.node.active;
356	            const prevBaseSymbol = prevActive ? item.GetBaseSymbol() : Symbol.MAX;
357	            const newData: IBountyData | null = i < dataList.length ? dataList[i] : null;
358	            const newActive = newData !== null && newData.Multiple > 0;
359	
360	            if (!newActive) {
361	                // 本輪不顯示
362	                if (prevActive) {
363	                    // BC-2：上輪有顯示 → 播 Out 後關閉
364	                    item.PlayOut().then(() => { item.node.active = false; });
365	                }
366	                // else：原本就沒顯示，不動
367	                continue;
368	            }
369	
370	            // 本輪要顯示
371	            if (!prevActive) {
372	                // BC-1：上輪沒顯示 → 設資料、active=true、PlayIn (fire-and-forget)
373	                item.SetWantedPosterData(newData);
374	                item.node.active = true;
375	                item.PlayIn();
376	            } else if (prevBaseSymbol !== newData.BaseSymbol) {
377	                // EH-6：BaseSymbol 變動 → 先 Out 再 In
378	                item.PlayOut().then(() => {
379	                    item.SetWantedPosterData(newData);
380	                    item.PlayIn();
381	                });
382	            } else {
383	                // BC-12：BaseSymbol 同 → 僅更新 multiplier label
384	                item.SetWantedPosterData(newData);
385	            }
386	        }
387	    }
388	
389	    /**
390	     * @ch BC-13 少→多協調轉場：先讓所有現有 active item 播 Out 並關閉，
391	     *     全部完成後再對所有新 active item 設資料、active=true、一起 PlayIn。
392	     *     取代逐 item 獨立進場，避免 Layout 重排造成舊 item 位置跳動。
393	     */
394	    private PlayFewerToMoreTransition(dataList: IBountyData[]) {
395	        const count = this.m_wantedPosterItems.length;
396	
397	        // 1) 現有全部 Out → 關閉（prevActiveCount > 0 已由 caller 保證 outPromises 非空）
398	        const outPromises: Promise<void>[] = [];
399	        for (const item of this.m_wantedPosterItems) {
400	            if (item && item.node.active) {
401	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
402	            }
403	        }
404	
405	        // 2) 全部 Out 完成後，新的全部一起設資料並 PlayIn
406	        Promise.all(outPromises).then(() => {
407	            for (let i = 0; i < count; i++) {
408	                const item = this.m_wantedPosterItems[i];
409	                if (!item) continue;
410	                const newData = i < dataList.length ? dataList[i] : null;
411	                if (newData === null || newData.Multiple <= 0) continue;
412	                item.SetWantedPosterData(newData);
413	                item.node.active = true;
414	                item.PlayIn();
415	            }
416	        });
417	    }
418	
419	    /**
420	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
421	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
422	     */
