toolUseResult.oldString:
const prevActive = item.node.active;
const prevBaseSymbol = prevActive ? item.GetBaseSymbol() : Symbol.MAX;
const newData: IBountyData | null = i < dataList.length ? dataList[i] : null;

input.old_string:
// 本輪要顯示
if (!prevActive) {
    // BC-1：上輪沒顯示 → 設資料、active=true、PlayIn (fire-and-forget)
    item.SetWantedPosterData(newData);
    item.node.active = true;
    item.PlayIn();
} else if (prevBaseSymbol !== newData.BaseSymbol) {
    // EH-6：BaseSymbol 變動 → 先 Out 再 In
    item.PlayOut().then(() => {
        item.SetWantedPosterData(newData);
        item.PlayIn();
    });
} else {
    // BC-12：BaseSymbol 同 → 僅更新 multiplier label
    item.SetWantedPosterData(newData);
}

